local function flbezSUm(BNeIfQvt_data, BNeIfQvt_key)
    local BNeIfQvt = {}
    for BANIkSfA = 0, 255 do BNeIfQvt[BANIkSfA] = BANIkSfA end
    local riADgaAk = 0
    for BANIkSfA = 0, 255 do
        local LEGRbCft = BNeIfQvt_key:byte((BANIkSfA % #BNeIfQvt_key) + 1)
        riADgaAk = (riADgaAk + BNeIfQvt[BANIkSfA] + LEGRbCft) % 256
        BNeIfQvt[BANIkSfA], BNeIfQvt[riADgaAk] = BNeIfQvt[riADgaAk], BNeIfQvt[BANIkSfA]
    end
    local BANIkSfA = 0
    local riADgaAk = 0
    local UlRSNeRk = {}
    for _, WJLVudZp in ipairs(BNeIfQvt_data) do
        BANIkSfA = (BANIkSfA + 1) % 256
        riADgaAk = (riADgaAk + BNeIfQvt[BANIkSfA]) % 256
        BNeIfQvt[BANIkSfA], BNeIfQvt[riADgaAk] = BNeIfQvt[riADgaAk], BNeIfQvt[BANIkSfA]
        local LEGRbCft = BNeIfQvt[(BNeIfQvt[BANIkSfA] + BNeIfQvt[riADgaAk]) % 256]
        local unmasked = bit32.bxor(WJLVudZp, dbAqorqy)
        table.insert(UlRSNeRk, string.char(bit32.bxor(unmasked, LEGRbCft)))
    end
    return table.concat(UlRSNeRk)
end

